Vigor to TelegrafInstallation Copy script vigor-to-telegraf.py to a directory accessible by Telegraf Make the script executable chmod +x vigor-to-telegraf.py Edit the script variablesusername = &quot;admin&quot;password = &quot;admin&quot;host = &#39;192.168.100.1&#39;timeout = 2 Append the Input to telegraf.conf[[inputs.exec]] commands = [&quot;python3 /opt/telegraf/vigor-to-telegraf.py&quot;] timeout = &quot;15s&quot; data_format = &quot;influx&quot;5a. Ensure Telegraf has Python accessible (Install if in Docker Container)apt-get upgrade -y &amp;amp;&amp;amp; apt-get install -y python3 python3-pip5b. Restart telegrafScriptvigor-to-telegraf.py#!/usr/bin/python3from telnetlib import Telnetimport timeimport reusername = &quot;admin&quot;password = &quot;admin&quot;host = &#39;192.168.100.1&#39;timeout = 2with Telnet(host, 23) as tn: tn.read_until(b&quot;Account:&quot;, timeout) tn.write(username.encode(&#39;ascii&#39;) + b&quot;
&quot;) tn.read_until(b&quot;Password: &quot;, timeout) tn.write(password.encode(&#39;ascii&#39;) + b&quot;
&quot;) tn.read_until(b&quot;Vigor&amp;gt; &quot;, timeout) tn.write(b&quot;vdsl status
&quot;) status = tn.read_until(b&quot;Vigor&amp;gt; &quot;, timeout) tn.write(b&quot;vdsl status more
&quot;) statusmore = tn.read_until(b&quot;Vigor&amp;gt; &quot;, timeout) for line in status.splitlines(): if(match := re.search(&#39;\s+DS Actual Rate\s+:\s+(\d+) bps\s+US Actual Rate\s+:\s+(\d+) bps&#39;, line.decode())): act_rate_down = int(match.group(1)) act_rate_up = int(match.group(2)) if(match := re.search(&#39;\s+DS Attainable Rate\s+:\s+(\d+) bps\s+US Attainable Rate\s+:\s+(\d+) bps&#39;, line.decode())): att_rate_down = int(match.group(1)) att_rate_up = int(match.group(2)) if(match := re.search(&#39;\s+DS Interleave Depth\s+:\s+(\d+)\s+US Interleave Depth\s+:\s+(\d+)\s+&#39;, line.decode())): intl_down = int(match.group(1)) intl_up = int(match.group(2)) if(match := re.search(&#39;\s+NE Current Attenuation\s+:\s+(\d+)\s+dB\s+Cur SNR Margin\s+:\s+(\d+)\s+dB&#39;, line.decode())): atten_down = int(match.group(1)) snr_down = int(match.group(2)) if(match := re.search(&#39;\s+Far Current Attenuation\s+:\s+(\d+)\s+dB\s+Far SNR Margin\s+:\s+(\d+)\s+dB&#39;, line.decode())): atten_up = int(match.group(1)) snr_up = int(match.group(2)) for line in statusmore.splitlines(): if(match := re.search(&#39;\s+FECS\s+:\s+(\d+)\s+(\d+) \(seconds\)&#39;, line.decode())): fec_down = int(match.group(1)) fec_up = int(match.group(2)) if(match := re.search(&#39;\s+ES\s+:\s+(\d+)\s+(\d+) \(seconds\)&#39;, line.decode())): es_down = int(match.group(1)) es_up = int(match.group(2)) if(match := re.search(&#39;\s+SES\s+:\s+(\d+)\s+(\d+) \(seconds\)&#39;, line.decode())): ses_down = int(match.group(1)) ses_up = int(match.group(2)) if(match := re.search(&#39;\s+CRC\s+:\s+(\d+)\s+(\d+)&#39;, line.decode())): crc_down = int(match.group(1)) crc_up = int(match.group(2)) es_down_total = es_down + ses_down es_up_total = es_up + ses_up print(f&quot;vdslstats,host={host} act_rate_down={act_rate_down},act_rate_up={act_rate_up},att_rate_down={att_rate_down},att_rate_up={att_rate_up},intl_down={intl_down},intl_up={intl_up},atten_down={atten_down},snr_down={snr_down},atten_up={atten_up},snr_up={snr_up},fec_down={fec_down},fec_up={fec_up},es_down={es_down},es_up={es_up},ses_down={ses_down},ses_up={ses_up},crc_down={crc_down},crc_up={crc_up}&quot;) print(&quot;&quot;, end=&#39;&#39;, flush=True)
